import{_ as a,o as i,c as s,a3 as t}from"./chunks/framework.CcF854Eu.js";const u=JSON.parse(`{"title":"FAQ","description":"","frontmatter":{"head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"FAQPage\\",\\"mainEntity\\":[{\\"@type\\":\\"Question\\",\\"name\\":\\"What shells are supported?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"amoxide supports Fish (fully), PowerShell 5.1+7, Zsh, Bash 3.2+, and Brush (bash-compatible). Nushell support is planned.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How is amoxide different from shell aliases in dotfiles?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Traditional aliases are static and defined once in .bashrc or .zshrc. amoxide adds: Profiles (named groups you can activate/deactivate), Project aliases (auto-loaded per directory like direnv), Parameterized aliases (template syntax for composable commands), and multiple active profiles with layered precedence.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Where are my aliases stored?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Global aliases are stored in ~/.config/amoxide/config.toml. Profile aliases are stored in ~/.config/amoxide/profiles.toml. Project aliases are stored in a .aliases file in the project directory.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I use amoxide alongside my existing shell aliases?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. amoxide aliases coexist with your shell's native aliases. If there is a name conflict, amoxide's alias takes precedence while it is active.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What is am-tui?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"am-tui is a separate binary (amoxide-tui) that provides an interactive terminal UI for managing aliases visually. Run it with: am tui. Install via: brew install sassman/tap/amoxide-tui\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"I changed my config file manually — how do I apply the changes without restarting my shell?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Run am init -f <shell> to reinitialise in place. This unloads all current aliases and reloads everything from your config, including any setting changes like use_abbr = true in Fish.\\"}}]}"]]},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}`),l={name:"faq.md"};function n(o,e,r,h,d,p){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="what-shells-are-supported" tabindex="-1">What shells are supported? <a class="header-anchor" href="#what-shells-are-supported" aria-label="Permalink to &quot;What shells are supported?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Shell</th><th>Status</th></tr></thead><tbody><tr><td>Fish</td><td>Fully supported and tested</td></tr><tr><td>PowerShell</td><td>Supported and tested (5.1 + 7)</td></tr><tr><td>Zsh</td><td>Supported, not yet tested</td></tr><tr><td>Bash</td><td>Supported (3.2+)</td></tr><tr><td>Brush</td><td>Supported (bash-compatible)</td></tr><tr><td>Nushell</td><td>Not yet implemented</td></tr></tbody></table><h2 id="how-is-this-different-from-shell-aliases-in-my-dotfiles" tabindex="-1">How is this different from shell aliases in my dotfiles? <a class="header-anchor" href="#how-is-this-different-from-shell-aliases-in-my-dotfiles" aria-label="Permalink to &quot;How is this different from shell aliases in my dotfiles?&quot;">​</a></h2><p>Traditional aliases are static — defined once in your <code>.bashrc</code> or <code>.zshrc</code>. amoxide adds:</p><ul><li><strong>Profiles</strong> — named groups you can activate/deactivate without editing files</li><li><strong>Project aliases</strong> — auto-loaded per directory, like direnv for aliases</li><li><strong>Parameterized aliases</strong> — template syntax for composable commands</li><li><strong>Multiple active profiles</strong> — layer aliases with clear precedence</li></ul><h2 id="where-are-my-aliases-stored" tabindex="-1">Where are my aliases stored? <a class="header-anchor" href="#where-are-my-aliases-stored" aria-label="Permalink to &quot;Where are my aliases stored?&quot;">​</a></h2><ul><li><strong>Global aliases:</strong> <code>~/.config/amoxide/config.toml</code></li><li><strong>Profile aliases:</strong> <code>~/.config/amoxide/profiles.toml</code></li><li><strong>Project aliases:</strong> <code>.aliases</code> file in the project directory</li></ul><h2 id="can-i-use-amoxide-alongside-my-existing-shell-aliases" tabindex="-1">Can I use amoxide alongside my existing shell aliases? <a class="header-anchor" href="#can-i-use-amoxide-alongside-my-existing-shell-aliases" aria-label="Permalink to &quot;Can I use amoxide alongside my existing shell aliases?&quot;">​</a></h2><p>Yes. amoxide aliases coexist with your shell&#39;s native aliases. If there&#39;s a name conflict, amoxide&#39;s alias takes precedence while it&#39;s active.</p><h2 id="what-is-am-tui" tabindex="-1">What is <code>am-tui</code>? <a class="header-anchor" href="#what-is-am-tui" aria-label="Permalink to &quot;What is `am-tui`?&quot;">​</a></h2><p>A separate binary (<code>amoxide-tui</code>) that provides an interactive terminal UI for managing aliases visually. Once installed, it integrates directly into <code>am</code>:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tui</span></span></code></pre></div><p>The <code>am tui</code> command launches the TUI — no need to remember a separate binary name. Quick install:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sassman/tap/amoxide-tui</span></span></code></pre></div><p>See <a href="/_preview/101/guide/installation#installing-am-tui">all installation options</a> for Shell Script, PowerShell, and Cargo.</p><h2 id="i-changed-my-config-file-manually-—-how-do-i-apply-the-changes-without-restarting-my-shell" tabindex="-1">I changed my config file manually — how do I apply the changes without restarting my shell? <a class="header-anchor" href="#i-changed-my-config-file-manually-—-how-do-i-apply-the-changes-without-restarting-my-shell" aria-label="Permalink to &quot;I changed my config file manually — how do I apply the changes without restarting my shell?&quot;">​</a></h2><p>Run <code>am init -f &lt;shell&gt;</code> to reinitialise in place. This unloads all current aliases and reloads everything from your config, including any setting changes like <a href="/_preview/101/advanced/config-files#fish-shell-fish"><code>use_abbr = true</code></a> in Fish. See <a href="/_preview/101/guide/setup#reinitialising-without-restarting">Reinitialising Without Restarting</a> for full details.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-OZ-6D" id="tab-HmV8LfL" checked><label data-title="Fish" for="tab-HmV8LfL">Fish</label><input type="radio" name="group-OZ-6D" id="tab-1ndxyH3"><label data-title="Zsh" for="tab-1ndxyH3">Zsh</label><input type="radio" name="group-OZ-6D" id="tab-mtVTkEi"><label data-title="PowerShell" for="tab-mtVTkEi">PowerShell</label><input type="radio" name="group-OZ-6D" id="tab-5XgjxcM"><label data-title="Bash" for="tab-5XgjxcM">Bash</label></div><div class="blocks"><div class="language-fish vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">fish</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">am</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> init -f fish </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> source</span></span></code></pre></div><div class="language-zsh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">zsh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eval</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zsh)&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(am init </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-f</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> powershell) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-join</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">`n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Invoke-Expression</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eval</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash)&quot;</span></span></code></pre></div></div></div>',19)])])}const g=a(l,[["render",n]]);export{u as __pageData,g as default};
